import { ref } from 'vue'
import { watchIgnorable } from '@vueuse/core'
import api from '../../../services/api'
import { PromoterOption, SettlementHistoryFilters, SettlementHistoryRecord } from '../types'

export type Pagination = {
    page: number
    perPage: number
    total: number
}

const makePaginationRef = () => ref<Pagination>({ page: 1, perPage: 10, total: 0 })

const toNumber = (value: unknown, fallback = 0): number => {
    const num = Number(value)
    return Number.isFinite(num) ? num : fallback
}

const toIsoString = (date: Date | null): string | undefined => {
    if (!date) return undefined
    if (Number.isNaN(date.getTime())) return undefined
    return date.toISOString()
}

export const useCommissionSettlementRecords = () => {
    const isLoading = ref(false)
    const records = ref<SettlementHistoryRecord[]>([])
    const promoters = ref<PromoterOption[]>([])
    const users = ref<{ id: number; firstName?: string; lastName?: string; nickname?: string; email?: string }[]>([])

    const pagination = makePaginationRef()
    const filters = ref<SettlementHistoryFilters>({
        promoterId: null,
        from: null,
        to: null,
    })

    const getUserDisplayName = (userId: number): string => {
        const user = users.value.find((u) => u.id === userId)
        if (!user) return `User #${userId}`
        if (user.nickname) return user.nickname
        if (user.firstName || user.lastName) return `${user.firstName || ''} ${user.lastName || ''}`.trim()
        return user.email || `User #${userId}`
    }

    const getPromoterName = (promoterId: number): string => {
        const promoter = promoters.value.find((p) => p.id === promoterId)
        return promoter?.userName || `Promoter #${promoterId}`
    }

    const fetchUsers = async () => {
        try {
            const { data } = await api.axiosInstance.get('/ops-user')
            users.value = data.data || []
        } catch (error) {
            console.error('Error fetching users:', error)
        }
    }

    const fetchPromoters = async () => {
        try {
            const { data } = await api.axiosInstance.get('/affiliate/promoter', { params: { limit: 100 } })
            const rawPromoters = (data.data || []) as PromoterOption[]
            promoters.value = rawPromoters.map((p) => ({
                ...p,
                userName: getUserDisplayName(p.userId),
            }))
        } catch (error) {
            console.error('Error fetching promoters:', error)
        }
    }

    const fetch = async () => {
        if (filters.value.promoterId === null) {
            records.value = []
            pagination.value.total = 0
            return
        }

        isLoading.value = true
        try {
            const params: Record<string, string | number> = {
                page: pagination.value.page,
                limit: pagination.value.perPage,
                promoterId: filters.value.promoterId,
            }

            const fromIso = toIsoString(filters.value.from)
            const toIso = toIsoString(filters.value.to)
            if (fromIso) params.from = fromIso
            if (toIso) params.to = toIso

            const { data } = await api.axiosInstance.get('/affiliate/settlement', { params })

            records.value = ((data.data || []) as SettlementHistoryRecord[]).map((record) => ({
                ...record,
                promoterName: getPromoterName(record.promoterId),
            }))

            ignorePaginationUpdates(() => {
                pagination.value = {
                    page: toNumber(data.page, pagination.value.page),
                    perPage: toNumber(data.limit, pagination.value.perPage),
                    total: toNumber(data.total),
                }
            })
        } catch (error) {
            console.error('Error fetching commission settlement records:', error)
            records.value = []
        } finally {
            isLoading.value = false
        }
    }

    const setPage = (page: number) => {
        pagination.value.page = page
    }

    const setPerPage = (perPage: number) => {
        pagination.value.perPage = perPage
        pagination.value.page = 1
    }

    const applyFilters = (nextFilters: Partial<SettlementHistoryFilters>) => {
        filters.value = {
            ...filters.value,
            ...nextFilters,
        }
        pagination.value.page = 1
    }

    const { ignoreUpdates: ignorePaginationUpdates } = watchIgnorable([pagination], fetch, {
        deep: true,
    })

    const init = async () => {
        await fetchUsers()
        await fetchPromoters()

        const firstPromoterId = promoters.value[0]?.id ?? null
        filters.value.promoterId = firstPromoterId

        await fetch()
    }

    init()

    return {
        isLoading,
        records,
        promoters,
        pagination,
        filters,
        fetch,
        setPage,
        setPerPage,
        applyFilters,
    }
}
