<script setup lang="ts">
import { computed, ref } from 'vue'
import CommissionSettlementRecordsTable from './widgets/CommissionSettlementRecordsTable.vue'
import { useCommissionSettlementRecords } from './composables/useCommissionSettlementRecords'

const { records, promoters, pagination, filters, isLoading, fetch, setPage, setPerPage, applyFilters } =
    useCommissionSettlementRecords()

const selectedPromoterId = computed<number | null>({
    get: () => filters.value.promoterId,
    set: (value) => {
        filters.value.promoterId = value
    },
})
const fromDate = ref<Date | null>(null)
const toDate = ref<Date | null>(null)

const promoterFilterOptions = computed(() =>
    promoters.value.map((p) => ({ value: p.id, text: p.userName || `Promoter #${p.id}` })),
)

const dateRangeError = computed(() => {
    if (!fromDate.value || !toDate.value) return ''
    if (fromDate.value.getTime() > toDate.value.getTime()) {
        return '開始日期不可晚於結束日期'
    }
    return ''
})

const onSearch = async () => {
    if (dateRangeError.value) return

    applyFilters({
        promoterId: selectedPromoterId.value,
        from: fromDate.value,
        to: toDate.value,
    })

    await fetch()
}

const clearFilters = async () => {
    selectedPromoterId.value = promoters.value[0]?.id ?? null
    fromDate.value = null
    toDate.value = null

    applyFilters({
        promoterId: selectedPromoterId.value,
        from: null,
        to: null,
    })

    await fetch()
}
</script>

<template>
    <h1 class="page-title">佣金支付紀錄</h1>

    <VaCard>
        <VaCardContent>
            <div class="flex flex-col md:flex-row gap-2 mb-4 justify-between flex-wrap items-start md:items-end">
                <div class="flex flex-col md:flex-row gap-2 justify-start flex-wrap items-start md:items-end">
                    <VaSelect
                        v-model="selectedPromoterId"
                        :options="promoterFilterOptions"
                        value-by="value"
                        text-by="text"
                        placeholder="選擇推廣夥伴"
                        class="w-full md:w-56"
                    />
                    <VaDateInput v-model="fromDate" label="開始日期" class="w-full md:w-56" clearable />
                    <VaDateInput v-model="toDate" label="結束日期" class="w-full md:w-56" clearable />
                </div>

                <div class="flex gap-2">
                    <VaButton preset="secondary" @click="clearFilters">清除</VaButton>
                    <VaButton :disabled="!!dateRangeError" @click="onSearch">搜尋</VaButton>
                </div>
            </div>

            <VaAlert v-if="dateRangeError" color="danger" class="mb-4" outline>
                {{ dateRangeError }}
            </VaAlert>

            <CommissionSettlementRecordsTable
                :records="records"
                :pagination="pagination"
                :loading="isLoading"
                @update:page="setPage"
                @update:perPage="setPerPage"
            />
        </VaCardContent>
    </VaCard>
</template>
