<script setup lang="ts">
import { defineVaDataTableColumns } from 'vuestic-ui'
import { computed, PropType } from 'vue'
import { useFormat } from '../../../composables/useFormat'
import { Pagination } from '../composables/useCommissionSettlementRecords'
import { SettlementHistoryRecord } from '../types'

const columns = defineVaDataTableColumns([
    { label: '支付日期', key: 'createdAt' },
    { label: '推廣夥伴', key: 'promoterName' },
    { label: '支付筆數', key: 'commissionRecordCount' },
    { label: '總支付金額', key: 'totalAmount' },
    { label: '備註', key: 'note' },
])

const props = defineProps({
    records: {
        type: Array as PropType<SettlementHistoryRecord[]>,
        required: true,
    },
    loading: { type: Boolean, default: false },
    pagination: { type: Object as PropType<Pagination>, required: true },
})

const emit = defineEmits<{
    (event: 'update:page', page: number): void
    (event: 'update:perPage', perPage: number): void
}>()

const totalPages = computed(() => Math.ceil(props.pagination.total / props.pagination.perPage))

const { formatDateTime } = useFormat()
const formatDate = (timestamp: string): string => {
    if (!timestamp) return '-'

    const parsedNumber = Number(timestamp)
    if (Number.isFinite(parsedNumber) && parsedNumber > 0) {
        return formatDateTime(parsedNumber)
    }

    const parsedIso = Date.parse(timestamp)
    if (Number.isFinite(parsedIso)) {
        return formatDateTime(parsedIso)
    }

    return timestamp
}

const onPerPageChange = (value: string | number) => {
    emit('update:perPage', Number(value))
}

const onPageChange = (value: string | number) => {
    emit('update:page', Number(value))
}
</script>

<template>
    <VaDataTable :columns="columns" :items="records" :loading="$props.loading">
        <template #cell(createdAt)="{ rowData }">
            {{ formatDate(rowData.createdAt) }}
        </template>

        <template #cell(promoterName)="{ rowData }">
            <div class="ellipsis max-w-[180px]">{{ rowData.promoterName || `Promoter #${rowData.promoterId}` }}</div>
        </template>

        <template #cell(commissionRecordCount)="{ rowData }">
            {{ Number(rowData.commissionRecordCount).toLocaleString() }}
        </template>

        <template #cell(totalAmount)="{ rowData }">
            <span class="font-semibold text-success">VND {{ Number(rowData.totalAmount).toLocaleString() }}</span>
        </template>

        <template #cell(note)="{ rowData }">
            <span>{{ rowData.note || '-' }}</span>
        </template>
    </VaDataTable>

    <VaAlert v-if="!$props.loading && records.length === 0" color="secondary" class="mt-4" outline>
        目前尚無傭金支付紀錄
    </VaAlert>

    <div class="flex flex-col-reverse md:flex-row gap-2 justify-between items-center py-2 mt-2">
        <div>
            <b>{{ $props.pagination.total }} results.</b>
            Results per page
            <VaSelect
                :model-value="$props.pagination.perPage"
                class="!w-20"
                :options="[10, 50, 100]"
                @update:modelValue="onPerPageChange"
            />
        </div>

        <div v-if="totalPages > 1" class="flex">
            <VaButton
                preset="secondary"
                icon="va-arrow-left"
                aria-label="Previous page"
                :disabled="$props.pagination.page === 1"
                @click="emit('update:page', $props.pagination.page - 1)"
            />
            <VaButton
                class="mr-2"
                preset="secondary"
                icon="va-arrow-right"
                aria-label="Next page"
                :disabled="$props.pagination.page === totalPages"
                @click="emit('update:page', $props.pagination.page + 1)"
            />
            <VaPagination
                :model-value="$props.pagination.page"
                buttons-preset="secondary"
                :pages="totalPages"
                :visible-pages="5"
                :boundary-links="false"
                :direction-links="false"
                @update:modelValue="onPageChange"
            />
        </div>
    </div>
</template>
